import Vue from 'vue';
import App from './App.vue'; // 确保这里没有写错路径
import ElementUI from 'element-ui';
import 'element-ui/lib/theme-chalk/index.css';
import router from './router'; // 确保引入了路由

Vue.use(ElementUI);

// 【关键修改点】
// 如果上面 import App 报错，尝试改成下面这样（兼容某些构建配置）：
// import App from './App.vue'; 
// 如果还是报错，请检查 App.vue 是否有 export default

new Vue({
  router,
  render: h => h(App)
}).$mount('#app');
